const output = [];
const nowMs = Date.now();

for (const item of $input.all()) {
  const data = item.json;

  const id = data.id;
  const user_id = data.user_id;
  const status = data.status;
  let reminder = data.reminder;

  let reminder_parameters = data.extra?.["напоминание"] ? JSON.parse(JSON.stringify(data.extra["напоминание"])) : null;
  let message = "";

  if (!reminder_parameters || !reminder_parameters["время"]) continue;

  const createdAtMs = Date.parse(data.created_at);
  const minutes = Math.floor((nowMs - createdAtMs) / 1000 / 60);

  const initialReminder = reminder;
  const initialTimeStr = JSON.stringify(reminder_parameters["время"]);

  // 1. Глобальная проверка статуса и наличия активных меток
  let statusFoundInActive = false;
  let hasActiveLabels = false;

  for (const key in reminder_parameters["время"]) {
    if (reminder_parameters["время"][key]["checked"] === 0) {
      hasActiveLabels = true;
      if (reminder_parameters["время"][key].hasOwnProperty(status)) {
        statusFoundInActive = true;
      }
    }
  }

  if (!hasActiveLabels || !statusFoundInActive) {
    reminder = false;
    if (initialReminder !== reminder) {
      output.push({ json: { id, user_id, reminder, reminder_parameters, message } });
    }
    continue;
  }

  // 2. СОРТИРОВКА: Получаем упорядоченный массив временных меток (от 10 к 20 и т.д.)
  const sortedKeys = Object.keys(reminder_parameters["время"]).sort((a, b) => parseInt(a, 10) - parseInt(b, 10));

  // 3. Цикл по времени (перебор по отсортированным ключам)
  for (const key of sortedKeys) {
    const label = reminder_parameters["время"][key];

    if (label["checked"] === 0) {
      const timeLimit = parseInt(key, 10);

      if (timeLimit <= minutes) {
        // Фиксируем изменение времени
        label["checked"] = 1;

        // Более поздняя метка затрет сообщение от предыдущей, если обе сработали одновременно
        if (label.hasOwnProperty(status)) {
          message = label[status];
        }
      }
    }
  }

  // 4. Анализ после цикла (проверка остатка)
  let hasZeroLeft = false;
  for (const key in reminder_parameters["время"]) {
    if (reminder_parameters["время"][key]["checked"] === 0) {
      hasZeroLeft = true;
      break;
    }
  }

  if (!hasZeroLeft) {
    reminder = false;
  }

  // 5. Формирование выхода
  const timeChanged = initialTimeStr !== JSON.stringify(reminder_parameters["время"]);
  const reminderChanged = initialReminder !== reminder;

  if (reminderChanged || timeChanged) {
    output.push({
      json: {
        id,
        user_id,
        reminder,
        reminder_parameters,
        message
      }
    });
  }
}

return output;

const output = [];

for (const item of $input.all()) {
  const data = item.json;

  // 1. Копируем входные данные "как есть"
  const id = data.id;
  const user_id = data.user_id;
  let reminder = data.reminder;
  let reminder_parameters = data.reminder_parameters ? JSON.parse(JSON.stringify(data.reminder_parameters)) : {};
  const message = data.message || "";

  // Получаем текст ошибки, если он передан
  const errorMessage = data.error || "";

  // 2. Если ошибка содержит маркер блокировки — вносим минимальные изменения
  if (errorMessage.includes("Forbidden")) {
    reminder = false;                             // Меняем ремайндер на false
    reminder_parameters["error"] = errorMessage; // Добавляем поле с причиной в корень параметров
  }

  // 3. Формируем единый выход для ноды БД
  output.push({
    json: {
      id,
      user_id,
      reminder,
      reminder_parameters,
      message
    }
  });
}

return output;

